const site='SOFT-1001';
const irradiation=300+Math.floor(Math.random()*500);
const temperature=24+Math.floor(Math.random()*15);
const voltage=360+Math.floor(Math.random()*40);
const panel_count=20;
const panels=Array.from({length:panel_count},(_,i)=>({panel_id:i+1,generation:20+Math.floor(Math.random()*15)}));
const actual_generation=panels.reduce((a,p)=>a+p.generation,0);
msg.topic=`solar/${site}/telemetry`;
msg.payload={site_identifier:site,timestamp:new Date().toISOString(),irradiation,temperature,voltage,panel_count,panels,actual_generation};
return msg;
